 1	import * as React from 'react';
 2	import { getCephPVCs, getCephPVs, getCephSC } from '@odf/ocs/utils';
 3	import {
 4	  PersistentVolumeClaimModel,
 5	  PersistentVolumeModel,
 6	  StorageClassModel,
 7	} from '@odf/shared/models';
 8	import { getName } from '@odf/shared/selectors';
 9	import {
10	  getPVCStatusGroups,
11	  getPVStatusGroups,
12	} from '@odf/shared/status/Inventory';
13	import {
14	  K8sResourceKind,
15	  StorageClassResourceKind,
16	  PersistentVolumeClaimKind,
17	} from '@odf/shared/types';
18	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
19	import { useK8sWatchResources } from '@openshift-console/dynamic-plugin-sdk';
20	import { ResourceInventoryItem } from '@openshift-console/dynamic-plugin-sdk-internal';
21	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
22	
23	const watchResources = {
24	  pvcs: {
25	    isList: true,
26	    kind: PersistentVolumeClaimModel.kind,
27	  },
28	  pvs: {
29	    isList: true,
30	    kind: PersistentVolumeModel.kind,
31	  },
32	  sc: {
33	    isList: true,
34	    kind: StorageClassModel.kind,
35	  },
36	};
37	
38	export const InventoryCard: React.FC = () => {
39	  const { t } = useCustomTranslation();
40	
41	  const resources = useK8sWatchResources(watchResources);
42	
43	  const pvcsLoaded = resources?.pvcs?.loaded;
44	  const pvcsLoadError = resources?.pvcs?.loadError;
45	  const pvcsData = (resources?.pvcs?.data ?? []) as PersistentVolumeClaimKind[];
46	
47	  const pvsLoaded = resources?.pvs?.loaded;
48	  const pvsLoadError = resources?.pvs?.loadError;
49	  const pvsData = (resources?.pvs?.data ?? []) as K8sResourceKind[];
50	
51	  const scData = (resources?.sc?.data ?? []) as StorageClassResourceKind[];
52	  const filteredCephSC = getCephSC(scData);
53	  const filteredSCNames = filteredCephSC.map(getName);
54	
55	  return (
56	    <Card>
57	      <CardHeader>
58	        <CardTitle>{t('Inventory')}</CardTitle>
59	      </CardHeader>
60	      <CardBody>
61	        <ResourceInventoryItem
62	          dataTest="inventory-pvc"
63	          isLoading={!pvcsLoaded}
64	          error={!!pvcsLoadError}
65	          kind={PersistentVolumeClaimModel as any}
66	          resources={getCephPVCs(filteredSCNames, pvcsData, pvsData)}
67	          mapper={getPVCStatusGroups}
68	          showLink={false}
69	        />
70	        <ResourceInventoryItem
71	          dataTest="inventory-pv"
72	          isLoading={!pvsLoaded}
73	          error={!!pvsLoadError}
74	          kind={PersistentVolumeModel as any}
75	          resources={getCephPVs(pvsData)}
76	          mapper={getPVStatusGroups}
77	          showLink={false}
78	        />
79	      </CardBody>
80	    </Card>
81	  );
82	};

